import { useState, useEffect, useMemo } from '@wordpress/element';
import { useGatewayForm } from '@arcwp/gateway-forms'; // Import the shared context hook
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import './style.css';

// Input Component (for forms)
const DateTimePickerFieldTypeInput = ({ config = {} }) => {
  const { register, setValue, watch, formState } = useGatewayForm(); // Get RHF methods from context
  const name = config.name;
  
  if (!name) {
    console.warn('DateTimePickerFieldTypeInput: No "name" provided in config');
    return null;
  }

  // Get error directly from context
  const fieldError = formState.errors[name];

  const {
    label,
    required = false,
    help,
    default: defaultValue = '',
    timeIntervals = 15,
    dateTimeFormat = 'MM/dd/yyyy h:mm aa',
    placeholder = 'Select date and time...',
    minDate,
    maxDate,
  } = config;

  const labelText = label || name.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  const currentValue = watch(name);
  const [selectedDateTime, setSelectedDateTime] = useState(null);

  // Parse initial value (expects MySQL datetime format: YYYY-MM-DD HH:MM:SS)
  useEffect(() => {
    if (currentValue) {
      const date = new Date(currentValue);
      if (!isNaN(date.getTime())) {
        setSelectedDateTime(date);
      }
    }
  }, [currentValue]);

  // Set initial/default value only once on mount
  useEffect(() => {
    if (currentValue === undefined && defaultValue) {
      setValue(name, defaultValue);
    }
  }, []);

  const handleChange = (date) => {
    setSelectedDateTime(date);

    // Format datetime as YYYY-MM-DD HH:MM:SS for database storage
    if (date) {
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const hours = String(date.getHours()).padStart(2, '0');
      const minutes = String(date.getMinutes()).padStart(2, '0');
      const seconds = String(date.getSeconds()).padStart(2, '0');
      setValue(name, `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`, { shouldValidate: true });
    } else {
      setValue(name, '');
    }
  };

  return (
    <div className="datetime-picker-field">
      {/* Hidden input for form registration */}
      <input type="hidden" {...register(name)} />

      <label htmlFor={name} className="datetime-picker-field__label">
        {labelText}
        {required && <span className="datetime-picker-field__required">*</span>}
      </label>

      <DatePicker
        selected={selectedDateTime}
        onChange={handleChange}
        showTimeSelect
        timeIntervals={timeIntervals}
        timeCaption="Time"
        dateFormat={dateTimeFormat}
        placeholderText={placeholder}
        minDate={minDate ? new Date(minDate) : null}
        maxDate={maxDate ? new Date(maxDate) : null}
        isClearable={!required}
        showMonthDropdown
        showYearDropdown
        dropdownMode="select"
        className={`datetime-picker-field__input ${fieldError ? 'datetime-picker-field__input--error' : ''}`}
      />

      {help && (
        <p className="datetime-picker-field__help">{help}</p>
      )}
      {fieldError && (
        <p className="datetime-picker-field__error">{fieldError.message}</p>
      )}
    </div>
  );
};

// Display Component (for grids and read-only views)
const DateTimePickerFieldTypeDisplay = ({ value, config }) => {
  // Handle null/undefined/empty values
  if (value === null || value === undefined || value === '') {
    return <span className="datetime-picker-field__display datetime-picker-field__display--empty">-</span>;
  }

  // Parse and format the datetime
  const date = new Date(value);
  if (isNaN(date.getTime())) {
    return <span className="datetime-picker-field__display datetime-picker-field__display--invalid">Invalid date</span>;
  }

  const formattedDateTime = date.toLocaleString('en-US', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });

  return <span className="datetime-picker-field__display">{formattedDateTime}</span>;
};

// Field Type Definition for registry
export const dateTimePickerFieldType = {
  type: 'datetime-picker',
  Input: DateTimePickerFieldTypeInput,
  Display: DateTimePickerFieldTypeDisplay,
  defaultConfig: {
    dateTimeFormat: 'MM/dd/yyyy h:mm aa',
    placeholder: 'Select date and time...',
    timeIntervals: 15,
  },
};

// Hook for easy usage
export const useDateTimePickerField = (config) => {
  return useMemo(() => ({
    Input: (props) => <DateTimePickerFieldTypeInput {...props} config={config} />,
    Display: (props) => <DateTimePickerFieldTypeDisplay {...props} config={config} />
  }), [config]);
};
